step.action:
Write context artifact to {{context_file}} in {{document_language}}:

      # Project Context — {{date}}

      ## Configuration
      - pm_tool: {{pm_tool or "not configured"}}
      - git_host: {{git_host or "not configured"}}
      - branch_pattern: {{branch_pattern or "not configured"}}
      - communication_language: {{communication_language}}
      - document_language: {{document_language}}

      ## Workspace Scope
      {{if is_multi_repo: list repos with name, role, localPath}}
      {{if not is_multi_repo: "Single-repo workspace"}}

      ## Git State
      - Current branch: {{current_branch}}
      - Recent commits:
      {{recent_commits}}
      - Uncommitted changes: {{git_status or "none"}}

      ## Existing Repo Context (via Nakiros MCP)
      {{if is_multi_repo:
        For each repo: "### {repo.name}\n{list of populated context fields (architecture, stack, conventions, api, llms) with updatedAt}"
      }}
      {{if not is_multi_repo: list of populated context fields with updatedAt}}

      ## Existing Workspace Context (via Nakiros MCP)
      {{if global_context: "- global: populated"}}
      {{if product_context: "- product: populated"}}
      {{if neither: "No workspace context generated yet — run /nak-workflow-generate-context to generate"}}

      ## Ticket Context
      {{ticket_context if present, else "No ticket provided"}}

Display a concise summary to the user:
      - Workspace: {{single or workspace-backed with repo count}}
      - Branch: {{current_branch}}
      - Repo context per repo: {{list of populated fields grouped by repo, with freshness}}
      - Workspace context: {{global: populated/empty, product: populated/empty}}
      - Ticket: {{ticketId or "none"}}
      - Artifact: {{context_file}}
